foreach (var field in ta.GetFields(BindingFlags.Public | BindingFlags.Static)) {
    Console.WriteLine($"  TimeoutAttribute field: {field.Name} = {field.GetValue(null)}");
}
foreach (var prop in ta.GetProperties(BindingFlags.Public | BindingFlags.Instance)) {
    Console.WriteLine($"  TimeoutAttribute prop: {prop.Name} type={prop.PropertyType}");
}

// Search for anything "Infinite" in the assembly
foreach (var t in asm.GetExportedTypes()) {
    foreach (var f in t.GetFields(BindingFlags.Public | BindingFlags.Static)) {
        if (f.Name.Contains("Infinite", StringComparison.OrdinalIgnoreCase)) {
            Console.WriteLine($"  FOUND: {t.FullName}.{f.Name} = {f.GetValue(null)}");
        }
    }
}

